const input = $('Offer Webhook').item.json;
const competitors = $('Read Competitors').all();
const patterns = $('Read Patterns').all();

// Competitor pricing landscape
const compPrices = competitors.map(c => ({
  name: c.json.name || c.json.Name || '',
  price: c.json.price || c.json.Price || 0,
  offer: c.json.offer_type || c.json['Offer Type'] || ''
}));

// Winning patterns for offer messaging
const winningPatterns = patterns
  .filter(p => (p.json.result || p.json.Result) === 'SCALE')
  .map(p => ({
    pattern: p.json.pattern || p.json.Pattern || '',
    emotion: p.json.emotion || p.json.Emotion || '',
    score: p.json.score || p.json.Score || 0
  }));

return {
  json: {
    strategy_input: input,
    competitor_prices: compPrices,
    winning_patterns: winningPatterns
  }
};

